            setupEventListeners();
        });

        // Render devices table
        function renderDevicesTable() {
            const tableBody = document.getElementById('devicesTableBody');
            tableBody.innerHTML = '';
            
            devices.forEach(device => {
                const lastSync = new Date(device.lastSync);
                const now = new Date();
                const hoursSinceSync = Math.floor((now - lastSync) / (1000 * 60 * 60));
                
                let syncStatusClass = 'recent';
                let syncStatusText = 'Just now';
                
                if (hoursSinceSync >= 1 && hoursSinceSync < 24) {
                    syncStatusClass = 'warning';
                    syncStatusText = `${hoursSinceSync}h ago`;
                } else if (hoursSinceSync >= 24) {
                    syncStatusClass = 'old';
                    syncStatusText = `${Math.floor(hoursSinceSync/24)}d ago`;
                } else {
                    const minutesSinceSync = Math.floor((now - lastSync) / (1000 * 60));
                    if (minutesSinceSync > 0) {
                        syncStatusText = `${minutesSinceSync}m ago`;
                    }
                }
                
                const row = document.createElement('tr');
                row.setAttribute('data-device-id', device.id);
                row.innerHTML = `
                    <td>
                        <div class="device-name-cell">
                            <div class="status-indicator ${device.status === 'active' ? 'status-active' : 'status-inactive'}"></div>
                            <div class="device-info">
                                <div>${device.name}</div>
                                <div class="device-id">${device.deviceId} | ${device.model}</div>
                            </div>
                        </div>
                    </td>
                    <td>${device.location}</td>
                    <td class="url-cell" title="${device.faceAuthUrl}">${device.faceAuthUrl}</td>
                    <td>
                        <div class="sync-status ${syncStatusClass}">
                            <i class="fas fa-sync-alt"></i> ${syncStatusText}
                        </div>
                    </td>
                    <td>
                        <span class="sync-status ${device.status === 'active' ? 'recent' : 'old'}">
