                                <i class="fas fa-sync-alt"></i>
                            </button>
                            <button class="action-btn remote-logs" title="Remote Logs">
                                <i class="fas fa-external-link-alt"></i>
                            </button>
                        </div>
                    </td>
                `;
                
                tableBody.appendChild(row);
            });
        }

        // Update statistics
        function updateStats() {
            const totalDevices = devices.length;
            const activeDevices = devices.filter(d => d.status === 'active').length;
            const inactiveDevices = totalDevices - activeDevices;
            
            document.getElementById('totalDevices').textContent = totalDevices;
            document.getElementById('activeDevices').textContent = activeDevices;
            document.getElementById('inactiveDevices').textContent = inactiveDevices;
        }

        // Setup event listeners
        function setupEventListeners() {
            // Open add device modal
            document.getElementById('openAddDeviceModal').addEventListener('click', function() {
                openDeviceModal(null);
            });
            
            // Close modal
            document.getElementById('closeModal').addEventListener('click', closeModal);
            document.getElementById('cancelForm').addEventListener('click', closeModal);
            
            // Close modal when clicking outside
            document.getElementById('deviceModal').addEventListener('click', function(e) {
                if (e.target === this) {
                    closeModal();
                }
            });
            
            // Tab switching
            document.querySelectorAll('.tab-btn').forEach(tab => {
                tab.addEventListener('click', function() {
                    const tabId = this.getAttribute('data-tab');
                    switchTab(tabId);
                });
            });
            
            // Device form submission
            document.getElementById('deviceForm').addEventListener('submit', function(e) {
                e.preventDefault();
                saveDevice();
            });
            
            // Refresh remote logs
            document.getElementById('refreshRemoteLogs').addEventListener('click', function() {
                refreshRemoteLogs();
            });
            
            // Download logs
            document.getElementById('downloadLogs').addEventListener('click', function() {
                downloadLogs();
            });
            
            // Search functionality
            document.getElementById('searchDevices').addEventListener('input', function() {
                filterDevices(this.value);
            });
            
            // Delegate events for device table actions
            document.getElementById('devicesTableBody').addEventListener('click', function(e) {
                const row = e.target.closest('tr');
                if (!row) return;
                
                const deviceId = parseInt(row.getAttribute('data-device-id'));
                const device = devices.find(d => d.id === deviceId);
                
                if (e.target.closest('.view-device')) {
                    openDeviceModal(deviceId);
                } else if (e.target.closest('.sync-now')) {
                    forceSync(deviceId);
                } else if (e.target.closest('.remote-logs')) {
                    openDeviceModal(deviceId, 'remote-logs');
                } else if (e.target.closest('td') && !e.target.closest('.action-btn')) {
                    openDeviceModal(deviceId, 'sync-logs');
                }
            });
        }

        // Open device modal
        function openDeviceModal(deviceId, activeTab = 'details') {
            const modal = document.getElementById('deviceModal');
            const modalTitle = document.getElementById('modalTitle');
            
            currentDeviceId = deviceId;
            
            if (deviceId) {
                // Edit mode
                const device = devices.find(d => d.id === deviceId);
                isEditMode = true;
                modalTitle.textContent = `Edit Device: ${device.name}`;
                
                // Fill form with device data
                document.getElementById('deviceName').value = device.name;
                document.getElementById('deviceId').value = device.deviceId;
                document.getElementById('deviceModel').value = device.model;
                document.getElementById('location').value = device.location;
                document.getElementById('faceAuthUrl').value = device.faceAuthUrl;
                document.getElementById('syncFrequency').value = device.syncFrequency;
                document.getElementById('deviceStatus').value = device.status;
                
                // Load sync logs for this device
                loadSyncLogs(deviceId);
                
                // Load remote logs for this device
                loadRemoteLogs(deviceId);
            } else {
                // Add mode
                isEditMode = false;
                modalTitle.textContent = 'Add New Device';
                
                // Reset form
                document.getElementById('deviceForm').reset();
                document.getElementById('syncFrequency').value = 15;
                document.getElementById('deviceStatus').value = 'active';
                
                // Clear logs
                document.getElementById('syncLogsContainer').innerHTML = '';
                document.getElementById('remoteLogContent').textContent = '';
            }
            
            // Show the modal and switch to the requested tab
            modal.style.display = 'flex';
            switchTab(activeTab);
        }

        // Close modal
        function closeModal() {
            document.getElementById('deviceModal').style.display = 'none';
            currentDeviceId = null;
            isEditMode = false;
        }

        // Switch between tabs
        function switchTab(tabId) {
            // Update active tab button
            document.querySelectorAll('.tab-btn').forEach(tab => {
                tab.classList.remove('active');
                if (tab.getAttribute('data-tab') === tabId) {
                    tab.classList.add('active');
                }
            });
            
            // Show active tab content
            document.querySelectorAll('.tab-content').forEach(content => {
                content.classList.remove('active');
                if (content.id === `${tabId}-tab`) {
                    content.classList.add('active');
                }
            });
            
            // If switching to remote logs tab and we have a device selected, load logs
            if (tabId === 'remote-logs' && currentDeviceId) {
                loadRemoteLogs(currentDeviceId);
            }
            
            // If switching to sync logs tab and we have a device selected, load logs
            if (tabId === 'sync-logs' && currentDeviceId) {
                loadSyncLogs(currentDeviceId);
            }
        }

        // Save device (add or edit)
