            const deviceName = document.getElementById('deviceName').value;
            const deviceId = document.getElementById('deviceId').value;
            const deviceModel = document.getElementById('deviceModel').value;
            const location = document.getElementById('location').value;
            const faceAuthUrl = document.getElementById('faceAuthUrl').value;
            const syncFrequency = document.getElementById('syncFrequency').value;
            const deviceStatus = document.getElementById('deviceStatus').value;
            
            if (isEditMode) {
                // Update existing device
                const deviceIndex = devices.findIndex(d => d.id === currentDeviceId);
                if (deviceIndex !== -1) {
                    devices[deviceIndex].name = deviceName;
                    devices[deviceIndex].deviceId = deviceId;
                    devices[deviceIndex].model = deviceModel;
                    devices[deviceIndex].location = location;
                    devices[deviceIndex].faceAuthUrl = faceAuthUrl;
                    devices[deviceIndex].syncFrequency = parseInt(syncFrequency);
                    devices[deviceIndex].status = deviceStatus;
                    devices[deviceIndex].lastSync = new Date().toISOString();
                }
            } else {
                // Add new device
                const newDevice = {
                    id: devices.length + 1,
                    name: deviceName,
                    deviceId: deviceId,
                    model: deviceModel || 'Unknown',
                    location: location,
                    status: deviceStatus,
                    lastSync: new Date().toISOString(),
                    faceAuthUrl: faceAuthUrl,
                    syncFrequency: parseInt(syncFrequency) || 15
                };
                
                devices.push(newDevice);
                
                // Create sync logs for new device
                syncLogs[newDevice.id] = [
                    { time: new Date().toLocaleString(), message: "Device registered successfully", status: "success" },
                    { time: new Date().toLocaleString(), message: "Initial configuration applied", status: "success" }
                ];
                
                // Create remote logs for new device
                remoteLogs[newDevice.id] = `[INFO] ${new Date().toLocaleString()} - Device ${deviceId} registered
[INFO] ${new Date().toLocaleString()} - Initial configuration loaded
[INFO] ${new Date().toLocaleString()} - Face authentication service initialized`;
            }
            
            // Update UI
            renderDevicesTable();
            updateStats();
            
            // Close modal
            closeModal();
            
            // Show success message
            alert(`Device "${deviceName}" has been ${isEditMode ? 'updated' : 'registered'} successfully!`);
        }

        // Load sync logs for a device
        function loadSyncLogs(deviceId) {
            const container = document.getElementById('syncLogsContainer');
            const logs = syncLogs[deviceId] || [];
            
            if (logs.length === 0) {
                container.innerHTML = `
                    <div class="no-data">
                        <i class="fas fa-history"></i>
                        <h3>No Sync Logs Available</h3>
                        <p>This device has not synchronized yet.</p>
                    </div>
                `;
                return;
            }
            
            let logsHTML = '';
            logs.forEach(log => {
                let iconClass = '';
                let icon = '';
                
                if (log.status === 'success') {
                    iconClass = 'success';
                    icon = 'fa-check-circle';
                } else if (log.status === 'error') {
                    iconClass = 'error';
                    icon = 'fa-times-circle';
                } else {
                    iconClass = 'warning';
                    icon = 'fa-exclamation-circle';
                }
                
                logsHTML += `
                    <div class="log-entry">
                        <div class="log-icon ${iconClass}">
                            <i class="fas ${icon}"></i>
                        </div>
                        <div class="log-info">
                            <div>${log.message}</div>
                            <div class="log-time">${log.time}</div>
                        </div>
                    </div>
                `;
            });
            
            container.innerHTML = logsHTML;
        }

        // Load remote logs for a device
        function loadRemoteLogs(deviceId) {
            const container = document.getElementById('remoteLogContent');
            const logs = remoteLogs[deviceId] || '';
            
            if (!logs) {
                container.textContent = 'No remote logs available for this device.';
                return;
            }
            
            container.textContent = logs;
            
            // Scroll to bottom to show latest logs
            container.scrollTop = container.scrollHeight;
        }

        // Refresh remote logs
        function refreshRemoteLogs() {
            if (!currentDeviceId) return;
            
            const btn = document.getElementById('refreshRemoteLogs');
            const originalHTML = btn.innerHTML;
            
            // Show loading state
            btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Refreshing...';
            btn.disabled = true;
            
            // Simulate API call delay
            setTimeout(() => {
                // In a real app, this would fetch fresh logs from the device
                // For demo, we'll just reload the current logs
                loadRemoteLogs(currentDeviceId);
                
                // Restore button
                btn.innerHTML = originalHTML;
                btn.disabled = false;
                
                // Show success message
                const device = devices.find(d => d.id === currentDeviceId);
                if (device) {
                    // Add a new log entry
                    const newLog = {
                        time: new Date().toLocaleString(),
                        message: "Remote logs refreshed manually",
                        status: "success"
                    };
                    
                    if (!syncLogs[currentDeviceId]) {
                        syncLogs[currentDeviceId] = [];
                    }
                    
                    syncLogs[currentDeviceId].unshift(newLog);
                    
                    // Update the sync logs tab if it's active
                    if (document.querySelector('.tab-btn[data-tab="sync-logs"]').classList.contains('active')) {
                        loadSyncLogs(currentDeviceId);
                    }
                }
            }, 1000);
        }

        // Download logs
        function downloadLogs() {
            if (!currentDeviceId) return;
            
            const device = devices.find(d => d.id === currentDeviceId);
            if (!device) return;
            
            const logs = remoteLogs[currentDeviceId] || 'No logs available';
            const blob = new Blob([logs], { type: 'text/plain' });
            const url = URL.createObjectURL(blob);
            const a = document.createElement('a');
            
            a.href = url;
            a.download = `logs-${device.deviceId}-${new Date().toISOString().slice(0, 10)}.txt`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

        // Force sync for a device
        function forceSync(deviceId) {
            const device = devices.find(d => d.id === deviceId);
            if (!device) return;
            
            // Update last sync time
            device.lastSync = new Date().toISOString();
            
            // Add a new log entry
            const newLog = {
                time: new Date().toLocaleString(),
                message: "Manual sync initiated",
                status: "success"
            };
            
            if (!syncLogs[deviceId]) {
                syncLogs[deviceId] = [];
            }
            
            syncLogs[deviceId].unshift(newLog);
            
            // Update UI
            renderDevicesTable();
            
            // Show success message
            alert(`Sync initiated for ${device.name}.`);
        }

        // Filter devices based on search input
        function filterDevices(searchTerm) {
            const rows = document.querySelectorAll('#devicesTableBody tr');
            const term = searchTerm.toLowerCase();
            
            rows.forEach(row => {
                const deviceId = parseInt(row.getAttribute('data-device-id'));
                const device = devices.find(d => d.id === deviceId);
                
                if (!device) return;
                
                const text = `
                    ${device.name} 
                    ${device.deviceId} 
                    ${device.model} 
                    ${device.location} 
                    ${device.faceAuthUrl}
                `.toLowerCase();
                
                if (text.includes(term)) {
                    row.style.display = '';
                } else {
                    row.style.display = 'none';
                }
            });
        }
    </script>
    
